mapper.select:
select t.* from tool_box t join ( select tool_id, MAX( CASE WHEN version IS NOT NULL THEN CAST( CASE WHEN POSITION('.' IN SUBSTRING(version, 2)) > 0 THEN SUBSTRING(SUBSTRING(version, 2), 1, POSITION('.' IN SUBSTRING(version, 2)) - 1) ELSE SUBSTRING(version, 2) END AS INTEGER) ELSE NULL END ) AS max_major from tool_box
and user_id =#{userId} and space_id is null
and space_id =#{spaceId}
and deleted = 0
GROUP BY tool_id ) t1 on t.tool_id = t1.tool_id
and t.deleted = 0
and t.user_id =#{userId} and t.space_id is null
and t.space_id =#{spaceId}
and ((t.version IS NULL AND t1.max_major IS NULL) or (CAST( CASE WHEN POSITION('.' IN SUBSTRING(t.version, 2)) > 0 THEN SUBSTRING(SUBSTRING(t.version, 2), 1, POSITION('.' IN SUBSTRING(t.version, 2)) - 1) ELSE SUBSTRING(t.version, 2) END AS INTEGER) = t1.max_major))
and (POSITION(#{content} IN t.name) > 0 or POSITION(#{content} IN t.description) > 0)
and t.status = #{status}
order by t.is_public desc, t.update_time desc
LIMIT #{limit} OFFSET #{start}

select * from tool_box t1 join (select tool_id, MAX( CASE WHEN version IS NOT NULL THEN CAST( CASE WHEN POSITION('.' IN SUBSTRING(version, 2)) > 0 THEN SUBSTRING(SUBSTRING(version, 2), 1, POSITION('.' IN SUBSTRING(version, 2)) - 1) ELSE SUBSTRING(version, 2) END AS INTEGER) ELSE NULL END ) AS max_version from tool_box
and deleted = 0 and POSITION(#{source} IN display_source) > 0
and (POSITION(#{content} IN name) > 0 or POSITION(#{content} IN description) > 0)
and tool_tag LIKE CONCAT('%', #{tags}, '%')
and ( is_public = 1
or user_id = #{adminUid}
)
group by tool_id) t2 on t1.tool_id = t2.tool_id
t1.tool_id in #{favorites}
and t1.deleted = 0 and POSITION(#{source} IN t1.display_source) > 0
and (POSITION(#{content} IN t1.name) > 0 or POSITION(#{content} IN t1.description) > 0)
and t1.tool_tag LIKE CONCAT('%', #{tags}, '%')
and ( t1.is_public = 1
or t1.user_id = #{adminUid}
) and (t1.version IS NULL AND t2.max_version IS NULL) OR ( CAST( CASE WHEN POSITION('.' IN SUBSTRING(t1.version, 2)) > 0 THEN SUBSTRING(SUBSTRING(t1.version, 2), 1, POSITION('.' IN SUBSTRING(t1.version, 2)) - 1) ELSE SUBSTRING(t1.version, 2) END AS INTEGER) = t2.max_version )
order by t1.top desc, t1.create_time desc,t1.favorite_count desc,t1.name asc order by t1.top desc, t1.favorite_count desc,t1.create_time desc,t1.name asc order by t1.top desc, t1.update_time desc,t1.favorite_count desc,t1.name asc order by t1.top desc, t1.name asc, t1.update_time desc
LIMIT #{limit} OFFSET #{start}

select * from tool_box where
deleted = 0

and id = #{toolId}

SELECT x.tool_id toolId , COUNT(*) botUsedCount FROM bot_tool_rel x
x.tool_id in
#{item}
group by x.tool_id;

SELECT count(1) FROM tool_box tb
and (POSITION(#{content} IN tb.name) > 0 or POSITION(#{content} IN tb.description) > 0)
and tb.tool_tag LIKE CONCAT('%', #{tags}, '%')
and tb.deleted = 0 and ( tb.is_public = 1
or tb.user_id = #{adminUid}
)

select t.* from tool_box t join ( select tool_id, MAX( CASE WHEN version IS NOT NULL THEN CAST( CASE WHEN POSITION('.' IN SUBSTRING(version, 2)) > 0 THEN SUBSTRING(SUBSTRING(version, 2), 1, POSITION('.' IN SUBSTRING(version, 2)) - 1) ELSE SUBSTRING(version, 2) END AS INTEGER) ELSE NULL END ) AS max_major from tool_box where deleted = 0 and tool_id IN
#{toolId}
GROUP BY tool_id ) t1 on t.tool_id = t1.tool_id where t.deleted = 0 and t.tool_id IN
#{toolId}
and ((t.version IS NULL AND t1.max_major IS NULL) or (CAST( CASE WHEN POSITION('.' IN SUBSTRING(t.version, 2)) > 0 THEN SUBSTRING(SUBSTRING(t.version, 2), 1, POSITION('.' IN SUBSTRING(t.version, 2)) - 1) ELSE SUBSTRING(t.version, 2) END AS INTEGER) = t1.max_major))
